//! # Virtio C Sürücüsü Shim Katmanı
//!
//! Bu modül, C ile yazılmış VirtIO sürücüsünü (`c_drivers/virtio.c`) Rust
//! çekirdek ortamına bağlayan köprü (shim/glue) katmanıdır.
//!
//! ## Görevler
//! - C sürücüsünden gelen IRQ (kesme) handler fonksiyonlarını kayıt eder
//! - IRQ vektör → C callback yönlendirmesi yapar (`shim_irq_trampoline`)
//! - VirtIO için `Hal` trait implementasyonu sağlar: DMA bellek ayırma/serbest bırakma,
//!   fiziksel↔sanal adres dönüşümü
//! - C kütüphanesine `malloc`/`free`/`printf` gibi standart fonksiyon öykünmesi sunar
//!
//! ## Güvenlik
//! Bu modülün büyük bölümü `unsafe` bloklar içerir; C ABI uyumluluğu ve
//! ham işaretçi (raw pointer) manipülasyonu zorunludur.

use alloc::string::String;
use core::ffi::{c_char, c_void, CStr};
use core::fmt::Write;
use core::hash::{BuildHasherDefault, Hasher};
use core::ptr::NonNull;
use hashbrown::HashMap;
use lazy_static::lazy_static;
use spin::Mutex;
use virtio_drivers::{BufferDirection, Hal, PhysAddr};

type ShimIrqHandler = unsafe extern "C" fn(u32, *mut c_void) -> i32;
static IRQ_SHIM_HANDLERS: Mutex<[Option<ShimIrqHandler>; 256]> = Mutex::new([None; 256]);
static IRQ_SHIM_DEVS: Mutex<[usize; 256]> = Mutex::new([0; 256]);

fn irq_to_vector(irq: u32) -> Option<u8> {
    if irq > u8::MAX as u32 {
        return None;
    }
    if irq < 32 {
        Some((irq as u8).wrapping_add(32))
    } else {
        Some(irq as u8)
    }
}

fn shim_irq_trampoline(vector: u8) {
    let handler = { IRQ_SHIM_HANDLERS.lock()[vector as usize] };
    if let Some(func) = handler {
        let dev = IRQ_SHIM_DEVS.lock()[vector as usize] as *mut c_void;
        unsafe {
            func(vector as u32, dev);
        }
    }
}

fn c_str_to_str(ptr: *const c_char) -> &'static str {
    if ptr.is_null() {
        return "";
    }
    unsafe { CStr::from_ptr(ptr).to_str().unwrap_or("") }
}

