    count: u64,
    /// Toplam gecikme (ortalama için)
    sum_ns: u64,
    /// Minimum gecikme (ns)
    min_ns: u64,
    /// Maksimum gecikme (ns)
    max_ns: u64,
}

impl LatencyHistogram {
    pub const fn new() -> Self {
        Self {
            buckets: [0; HISTOGRAM_BUCKETS],
            count: 0,
            sum_ns: 0,
            min_ns: u64::MAX,
            max_ns: 0,
        }
    }

    /// Gecikme örneği ekler (nanosaniye).
    pub fn record(&mut self, latency_ns: u64) {
        self.count += 1;
        self.sum_ns += latency_ns;
