// PANO VERİSİ
// ============================================================================

/// Pano veri türleri
#[derive(Clone, Debug)]
pub enum ClipboardData {
    /// Veri yok
    Empty,
    /// Düz metin
    Text(String),
    /// Zengin metin (HTML/RTF)
    RichText { html: String, plain: String },
    /// Resim verisi
    Image {
        width: usize,
        height: usize,
        data: Vec<u32>,
    },
    /// Dosya yolları
    Files(Vec<String>),
    /// URL
    Url(String),
    /// Format tanımlayıcılı özel veri
    Custom { format: String, data: Vec<u8> },
