            running: AtomicBool::new(false),
            next_id: AtomicU64::new(1),
            entries: Mutex::new(Vec::new()),
            command_queue: MailboxRing::with_capacity_pow2(NOTIFICATION_COMMAND_QUEUE_CAPACITY),
