//!  │ hash(fiziksel_adres) → FutexQueue        │
//!  │  ┌─────────────────────────────────────┐ │
//!  │  │ FutexWaiter(task=10, bitset=0xFFFF) │ │
//!  │  │ FutexWaiter(task=11, bitset=0xFFFF) │ │
//!  │  └─────────────────────────────────────┘ │
